import{_ as e,o,c as d,ag as a}from"./chunks/framework.HG0H2VLS.js";const p=JSON.parse('{"title":"ActionsMenu (CC) — Figma Notes","description":"","frontmatter":{},"headers":[],"relativePath":"public/demos/src/cc/patterns/ActionsMenu/ActionsMenu.figma-notes.md","filePath":"public/demos/src/cc/patterns/ActionsMenu/ActionsMenu.figma-notes.md"}'),n={name:"public/demos/src/cc/patterns/ActionsMenu/ActionsMenu.figma-notes.md"};function c(i,t,r,s,l,h){return o(),d("div",null,[...t[0]||(t[0]=[a('<h1 id="actionsmenu-cc-—-figma-notes" tabindex="-1">ActionsMenu (CC) — Figma Notes <a class="header-anchor" href="#actionsmenu-cc-—-figma-notes" aria-label="Permalink to &quot;ActionsMenu (CC) — Figma Notes&quot;">​</a></h1><p><strong>Figma:</strong> <a href="https://www.figma.com/design/ETKqleZdpertwFEo40YB5n/Affino-CC-Hybrid--Design-System?node-id=4146-6684" target="_blank" rel="noreferrer"><code>node 4146:6684</code></a> (CC Hybrid Design System) <strong>Tier:</strong> Pattern <strong>Files:</strong> <code>ActionsMenu.css</code>, <code>ActionsMenu.html</code>, <code>ActionsMenu.figma.ts</code>, <code>ActionsMenu.figma-notes.md</code></p><hr><h2 id="variant-matrix" tabindex="-1">Variant matrix <a class="header-anchor" href="#variant-matrix" aria-label="Permalink to &quot;Variant matrix&quot;">​</a></h2><p>Single component (no Type/Device/State axes). Figma renders one ActionsMenu instance with 6 internal <code>MenuBtn</code> layers. The Figma design shows the first button (Sparkles) with the hover-state background applied — that is a visual showcase of the hover state, not a permanent treatment of the first button.</p><table tabindex="0"><thead><tr><th>Node</th><th>Variant</th><th>Notes</th></tr></thead><tbody><tr><td><code>4146:6684</code></td><td>Default</td><td>Container + 6 stacked MenuBtn icon buttons. First button shown in <code>.is-hover</code> state in the Figma reference.</td></tr></tbody></table><p>Per-button states (CSS-only — no JS needed):</p><ul><li>Default (no bg, icon at rest colour)</li><li>Hover (<code>:hover</code> or <code>.is-hover</code> → <code>--cc-actions-menu-secondary-bg</code>)</li><li>Focus (<code>:focus-visible</code> → 2px brand outline, -2px offset)</li><li>Disabled (opacity 40%, not-allowed)</li></ul><hr><h2 id="css-class-mapping" tabindex="-1">CSS class mapping <a class="header-anchor" href="#css-class-mapping" aria-label="Permalink to &quot;CSS class mapping&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Figma</th><th>CSS</th></tr></thead><tbody><tr><td>Wrapper (<code>ActionsMenu</code>)</td><td><code>.actions-menu</code> (<code>&lt;div&gt;</code> or <code>&lt;aside&gt;</code>)</td></tr><tr><td><code>MenuBtn</code> (each icon row)</td><td><code>.actions-menu__btn</code> (<code>&lt;button type=&quot;button&quot;&gt;</code>)</td></tr><tr><td>Icon inside button</td><td><code>&lt;i data-lucide=&quot;icon-name&quot;&gt;</code></td></tr></tbody></table><p><code>MenuBtn</code> is implemented inline as a scoped class rather than extracted as its own component. The Figma layer named <code>MenuBtn</code> uses direct node IDs (no <code>I&lt;instance&gt;;&lt;source&gt;</code> signature), indicating it&#39;s a styled layer rather than a Component Instance — so inline scoped CSS is appropriate.</p><hr><h2 id="token-mapping" tabindex="-1">Token mapping <a class="header-anchor" href="#token-mapping" aria-label="Permalink to &quot;Token mapping&quot;">​</a></h2><h3 id="wrapper" tabindex="-1">Wrapper <a class="header-anchor" href="#wrapper" aria-label="Permalink to &quot;Wrapper&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th><th>Value</th></tr></thead><tbody><tr><td>Background</td><td><code>var(--cc-actions-menu-primary-bg)</code></td><td><code>#d0dbe1</code> (CC light), <code>#334155</code> (CC dark)</td></tr><tr><td>Padding</td><td><code>var(--ai-spacing-4) var(--ai-spacing-3)</code></td><td>12px / 8px</td></tr><tr><td>Gap</td><td><code>var(--ai-spacing-3)</code></td><td>8px</td></tr><tr><td>Display</td><td><code>inline-flex</code> column, centred</td><td>—</td></tr></tbody></table><p>Width is implicit: 40px button + 2 × 8px horizontal padding = <strong>56px</strong> total. No explicit <code>width</code> set — wrapper sizes to its content.</p><h3 id="button" tabindex="-1">Button <a class="header-anchor" href="#button" aria-label="Permalink to &quot;Button&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Property</th><th>Token</th></tr></thead><tbody><tr><td>Width × Height</td><td><code>var(--ai-spacing-8)</code> × <code>var(--ai-spacing-8)</code> (40 × 40)</td></tr><tr><td>Border-radius</td><td><code>var(--ai-radius-md)</code> (8px)</td></tr><tr><td>Background (default)</td><td><code>transparent</code></td></tr><tr><td>Background (hover / <code>.is-hover</code>)</td><td><code>var(--cc-actions-menu-secondary-bg)</code></td></tr><tr><td>Icon size</td><td><code>var(--ai-icon-size-md)</code> (20px)</td></tr><tr><td>Icon colour</td><td><code>var(--cc-actions-menu-icon)</code></td></tr><tr><td>Focus outline</td><td><code>2px solid var(--ai-surface-brand)</code>, offset <code>-2px</code></td></tr></tbody></table><hr><h2 id="token-additions-2026-05-27" tabindex="-1">Token additions (2026-05-27) <a class="header-anchor" href="#token-additions-2026-05-27" aria-label="Permalink to &quot;Token additions (2026-05-27)&quot;">​</a></h2><p>A new <code>--cc-actions-menu-*</code> token family was added to the CC Semantic tokens (<code>CCLight.tokens.json</code> + <code>CCDark.tokens.json</code>):</p><table tabindex="0"><thead><tr><th>Token</th><th>Light value</th><th>Dark value</th></tr></thead><tbody><tr><td><code>--cc-actions-menu-primary-bg</code></td><td><code>#d0dbe1</code></td><td><code>#334155</code></td></tr><tr><td><code>--cc-actions-menu-secondary-bg</code></td><td><code>#e7edf0</code></td><td><code>#1e293b</code></td></tr><tr><td><code>--cc-actions-menu-icon</code></td><td><code>#335562</code></td><td><code>#cbd5e1</code></td></tr></tbody></table><p>The three values coincide with existing <code>--ai-surface-contrast</code>, <code>--ai-surface-secondary</code>, and <code>--ai-icon-primary</code> in CC light — but the dedicated <code>--cc-actions-menu-*</code> family was kept so future re-themes can move the actions menu independently of the semantic surfaces.</p><p><strong>SD warning:</strong> the token compile emitted a collision warning for <code>--cc-actions-menu-icon</code> (it appears twice in the source with different values — <code>#667f89</code> then <code>#335562</code> in light, <code>#94a3b8</code> then <code>#cbd5e1</code> in dark). CSS cascade resolves to the second value but the source JSON should be de-duplicated. Worth a follow-up.</p><p>No other token gaps.</p><hr><h2 id="icon-inventory" tabindex="-1">Icon inventory <a class="header-anchor" href="#icon-inventory" aria-label="Permalink to &quot;Icon inventory&quot;">​</a></h2><p>Figma reference uses (top → bottom):</p><table tabindex="0"><thead><tr><th>#</th><th>Lucide name</th><th>data-name in Figma</th><th>Demo <code>aria-label</code></th></tr></thead><tbody><tr><td>1</td><td><code>sparkles</code></td><td><code>Icon/24px/Sparkles</code></td><td>AI suggestions</td></tr><tr><td>2</td><td><code>info</code></td><td><code>Icon/24px/Info</code></td><td>Info</td></tr><tr><td>3</td><td><code>star</code></td><td><code>Icon/24px/Star</code></td><td>Favourite</td></tr><tr><td>4</td><td><code>a-large-small</code></td><td><code>Icon/24px/ALargeSmall</code></td><td>Text size</td></tr><tr><td>5</td><td><code>minimize-2</code></td><td><code>Icon/24px/Minimize2</code></td><td>Minimise</td></tr><tr><td>6</td><td><code>printer</code></td><td><code>Icon/24px/Printer</code></td><td>Print</td></tr></tbody></table><p>The actual icon set / labels depend on the consuming context. The demo&#39;s labels are descriptive placeholders.</p><hr><h2 id="accessibility" tabindex="-1">Accessibility <a class="header-anchor" href="#accessibility" aria-label="Permalink to &quot;Accessibility&quot;">​</a></h2><ul><li>Each button is <code>&lt;button type=&quot;button&quot; aria-label=&quot;…&quot;&gt;</code> (icon-only).</li><li>40 × 40px exceeds the WCAG 44 × 44 touch-target minimum when the rest of the surrounding context provides additional spacing (the 8px vertical gap between buttons in this menu is the spacing).</li><li>Focus uses a 2px brand-coloured inset outline (offset −2px) so the ring stays within the button bounds.</li><li>The hover treatment also serves as the implicit selected/active visual — consumers that need a separate selected state can add <code>.is-hover</code> or a dedicated <code>--selected</code> modifier.</li></ul><hr><h2 id="dependencies" tabindex="-1">Dependencies <a class="header-anchor" href="#dependencies" aria-label="Permalink to &quot;Dependencies&quot;">​</a></h2><ul><li>None directly. Uses base tokens + Lucide for icons.</li></ul><hr><h2 id="history" tabindex="-1">History <a class="header-anchor" href="#history" aria-label="Permalink to &quot;History&quot;">​</a></h2><ul><li>2026-05-27: Initial pattern scaffold. Built from Figma component <code>4146:6684</code> (CC Hybrid Design System). New <code>--cc-actions-menu-*</code> token family added to the CC Semantic source JSONs and regenerated. MenuBtn implemented inline (no separate component) since the Figma node IDs are direct rather than Component-instance-signatures.</li></ul>',40)])])}const m=e(n,[["render",c]]);export{p as __pageData,m as default};
